import type { HardhatPlugin } from "../../../types/plugins.js";

import { styleText } from "node:util";

import { getLoadedPlugins } from "./loaded-plugins-registry.js";

export function warnAboutUnusedLoadedPlugins(
  resolvedPlugins: HardhatPlugin[],
  printError: (message: string) => void = (message) => console.error(message),
  loadedPlugins: Iterable<HardhatPlugin> = getLoadedPlugins().values(),
): void {
  const resolvedIds = new Set(resolvedPlugins.map((p) => p.id));

  const unused: HardhatPlugin[] = [];
  for (const plugin of loadedPlugins) {
    if (!resolvedIds.has(plugin.id)) {
      unused.push(plugin);
    }
  }

  if (unused.length === 0) {
    return;
  }

  const lines: string[] = [
    "",
    styleText(["bold", "yellow"], "Warning:") +
      " the following plugins were imported but are not present in the `plugins` array of your config:",
    "",
  ];

  for (const plugin of unused) {
    const name =
      plugin.npmPackage !== undefined && plugin.npmPackage !== null
        ? `${plugin.npmPackage}  (id: ${plugin.id})`
        : plugin.id;
    lines.push(`  - ${name}`);
  }

  lines.push(
    "",
    "  Add them to the `plugins` array, or remove the unused plugin import(s) to silence this warning.",
    "",
  );

  printError(lines.join("\n"));
}

import type { DeploymentResult } from "@nomicfoundation/ignition-core";

export enum UiFutureStatusType {
  UNSTARTED = "UNSTARTED",
  SUCCESS = "SUCCESS",
  TIMEDOUT = "TIMEDOUT",
  ERRORED = "ERRORED",
  HELD = "HELD",
}

export enum UiStateDeploymentStatus {
  UNSTARTED = "UNSTARTED",
  DEPLOYING = "DEPLOYING",
  COMPLETE = "COMPLETE",
}

export interface UiFutureUnstarted {
  type: UiFutureStatusType.UNSTARTED;
}

export interface UiFutureSuccess {
  type: UiFutureStatusType.SUCCESS;
  result?: string;
}

export interface UiFutureTimedOut {
  type: UiFutureStatusType.TIMEDOUT;
}

export interface UiFutureErrored {
  type: UiFutureStatusType.ERRORED;
  message: string;
}

export interface UiFutureHeld {
  type: UiFutureStatusType.HELD;
  heldId: number;
  reason: string;
}

export type UiFutureStatus =
  | UiFutureUnstarted
  | UiFutureSuccess
  | UiFutureTimedOut
  | UiFutureErrored
  | UiFutureHeld;

export interface UiFuture {
  status: UiFutureStatus;
  futureId: string;
}

export type UiBatches = UiFuture[][];

export interface UiState {
  status: UiStateDeploymentStatus;
  chainId: number | null;
  moduleName: string | null;
  deploymentDir: string | undefined | null;
  batches: UiBatches;
  currentBatch: number;
  result: DeploymentResult | null;
  warnings: string[];
  isResumed: boolean | null;
  maxFeeBumps: number;
  gasBumps: Record<string, number>;
  disableFeeBumping: boolean | null;
  strategy: string | null;
}

export interface AddressMap {
  [label: string]: string;
}

import type { ConfigHooks } from "hardhat/types/hooks";

import { createDebug } from "@nomicfoundation/hardhat-utils/debug";

import {
  getDevKeystoreFilePath,
  getDevKeystorePasswordFilePath,
  getKeystoreFilePath,
} from "../utils/get-keystore-file-path.js";

const log = createDebug("hardhat:keystore:hook-handlers:config");

export default async (): Promise<Partial<ConfigHooks>> => {
  const handlers: Partial<ConfigHooks> = {
    resolveUserConfig: async (
      userConfig,
      resolveConfigurationVariable,
      next,
    ) => {
      const resolvedConfig = await next(
        userConfig,
        resolveConfigurationVariable,
      );

      const defaultKeystoreFilePath = await getKeystoreFilePath();
      const defaultDevKeystoreFilePath = await getDevKeystoreFilePath();
      const defaultDevKeystorePasswordFilePath =
        await getDevKeystorePasswordFilePath();

      log(`path to keystore file: ${defaultKeystoreFilePath}`);

      return {
        ...resolvedConfig,
        keystore: {
          filePath: defaultKeystoreFilePath,
          devFilePath: defaultDevKeystoreFilePath,
          devPasswordFilePath: defaultDevKeystorePasswordFilePath,
        },
      };
    },
  };

  return handlers;
};

import type { HardhatUserConfig } from "hardhat/config";
import type { HardhatUserConfigValidationError } from "hardhat/types/hooks";

import {
  getUnprefixedHexString,
  isHexString,
} from "@nomicfoundation/hardhat-utils/hex";
import { validateUserConfigZodType } from "@nomicfoundation/hardhat-zod-utils";
import { z } from "zod";

const addressSchema = z
  .string()
  .refine(
    (val) => isHexString(val) && getUnprefixedHexString(val).length === 40,
    {
      message:
        "Each ledger account must be a valid 42 character hexadecimal string",
    },
  );

const ledgerUserConfigSchema = z.object({
  ledgerAccounts: z.array(addressSchema).optional(),
  ledgerOptions: z
    .object({
      derivationFunction: z.function().optional(),
    })
    .optional(),
});

export async function validateLedgerUserConfig(
  userConfig: HardhatUserConfig,
): Promise<HardhatUserConfigValidationError[]> {
  if (userConfig.networks === undefined) {
    return [];
  }

  const networksErrors = [];

  for (const [networkName, network] of Object.entries(userConfig.networks)) {
    const errors = validateUserConfigZodType(
      {
        ledgerAccounts: network.ledgerAccounts,
        ledgerOptions: network.ledgerOptions,
      },
      ledgerUserConfigSchema,
    ).map((err) => {
      err.message = `network "${networkName}" - ${err.message}`;
      return err;
    });

    networksErrors.push(...errors);
  }

  return networksErrors;
}

