pragma solidity ^0.8.0;

contract Calculator {
    uint256 public result;
    uint256 public lastOperation;

    event Operation(string op, uint256 a, uint256 b, uint256 result);

    function add(uint256 a, uint256 b) public returns (uint256) {
        result = a + b;
        lastOperation = result;
        emit Operation("add", a, b, result);
        return result;
    }

    function subtract(uint256 a, uint256 b) public returns (uint256) {
        require(a >= b, "Calculator: subtraction underflow");
        result = a - b;
        lastOperation = result;
        emit Operation("subtract", a, b, result);
        return result;
    }

    function multiply(uint256 a, uint256 b) public returns (uint256) {
        result = a * b;
        lastOperation = result;
        emit Operation("multiply", a, b, result);
        return result;
    }

    function divide(uint256 a, uint256 b) public returns (uint256) {
        require(b != 0, "Calculator: division by zero");
        result = a / b;
        lastOperation = result;
        emit Operation("divide", a, b, result);
        return result;
    }

    function reset() public {
        result = 0;
        lastOperation = 0;
    }
}

import type { HardhatEthers } from "@nomicfoundation/hardhat-ethers/types";
import type { Addressable } from "ethers";

import { toBigInt } from "@nomicfoundation/hardhat-utils/bigint";
import { ensureError } from "@nomicfoundation/hardhat-utils/error";
import { assert as chaiAssert } from "chai";

import { getAddressOf } from "./account.js";
import { assertCanBeConvertedToBigint } from "./asserts.js";

export interface BalanceChangeOptions {
  includeFee?: boolean;
}

export function getAddresses(
  accounts: Array<Addressable | string>,
): Promise<string[]> {
  return Promise.all(accounts.map((account) => getAddressOf(account)));
}

export async function getBalances(
  ethers: HardhatEthers,
  accounts: Array<Addressable | string>,
  blockNumber: number,
): Promise<bigint[]> {
  return await Promise.all(
    accounts.map(async (account) => {
      const address = await getAddressOf(account);

      let result;
      try {
        result = await ethers.provider.getBalance(address, blockNumber);
      } catch (cause) {
        try {
          chaiAssert.fail(
            "Failed to get the balance of the account " + address,
          );
        } catch (e) {
          ensureError(e);
          e.cause = cause;

          throw e;
        }
      }

      assertCanBeConvertedToBigint(result);

      return toBigInt(result);
    }),
  );
}

import { HardhatError } from "@nomicfoundation/hardhat-errors";
import { deepClone, isObject } from "@nomicfoundation/hardhat-utils/lang";

const PRIMITIVE = [
  "bigint",
  "boolean",
  "function",
  "number",
  "string",
  "symbol",
];

export async function deepCopy<T = any>(value: T): Promise<T> {
  // The function 'deepClone' from 'hardhat-utils' cannot be used to replace this function, it won't properly clone
  // the value. The reason is that 'deepClone' doesn't handle certain custom cases,
  // such as skipping objects with a getAddress method and treating primitive types explicitly.
  // These custom checks are necessary for correct behavior in our use case.

  if (
    value === null ||
    value === undefined ||
    PRIMITIVE.includes(typeof value)
  ) {
    return value;
  }

  // Keep any Addressable
  if (
    isObject(value) &&
    "getAddress" in value &&
    typeof value.getAddress === "function"
  ) {
    return value;
  }

  if (Array.isArray(value)) {
    return await deepClone(value);
  }

  if (isObject(value)) {
    const newV: any = {};

    return Object.keys(value).reduce((accum, key) => {
      accum[key] = value[key];
      return accum;
    }, newV);
  }

  throw new HardhatError(
    HardhatError.ERRORS.HARDHAT_ETHERS.GENERAL.UNSUPPORTED_TYPE_FOR_DEEP_COPY,
    {
      value,
      type: typeof value,
    },
  );
}

import type { UiFuture, UiState } from "../types.js";

import { UiFutureStatusType } from "../types.js";

export function calculateBatchDisplay(state: UiState): {
  text: string;
  height: number;
} {
  const batch = state.batches[state.currentBatch - 1];
  const height = batch.length + 2;

  let text = `Batch #${state.currentBatch}\n`;

  text += batch
    .sort((a, b) => a.futureId.localeCompare(b.futureId))
    .map((v) => _futureStatus(v, state.gasBumps, state.maxFeeBumps))
    .join("\n");

  text += "\n";

  return { text, height };
}

function _futureStatus(
  future: UiFuture,
  gasBumps: Record<string, number>,
  maxFeeBumps: number,
): string {
  switch (future.status.type) {
    case UiFutureStatusType.UNSTARTED: {
      const gas = gasBumps[future.futureId];
      return `  Executing ${future.futureId}${
        gas !== undefined
          ? ` - bumping gas fee (${gas}/${maxFeeBumps})...`
          : "..."
      }`;
    }
    case UiFutureStatusType.SUCCESS: {
      return `  Executed ${future.futureId}`;
    }
    case UiFutureStatusType.TIMEDOUT: {
      return `  Timed out ${future.futureId}`;
    }
    case UiFutureStatusType.ERRORED: {
      return `  Failed ${future.futureId}`;
    }
    case UiFutureStatusType.HELD: {
      return `  Held ${future.futureId}`;
    }
  }
}

import type { UiState } from "../types.js";

import { styleText } from "node:util";

import { assertHardhatInvariant } from "@nomicfoundation/hardhat-errors";

import { pathFromCwd } from "./cwd-relative-path.js";

export function calculateDeployingModulePanel(state: UiState): string {
  let deployingMessage = `Hardhat Ignition 🚀

`;

  if (state.isResumed === true) {
    assertHardhatInvariant(
      state.deploymentDir !== null && state.deploymentDir !== undefined,
      "Deployment dir is undefined",
    );
    deployingMessage += `${styleText(
      "bold",
      `Resuming existing deployment from ${pathFromCwd(state.deploymentDir)}`,
    )}

`;
  }

  deployingMessage += `${styleText(
    "bold",
    `Deploying [ ${state.moduleName ?? "unknown"} ]${_calculateStrategySuffix(
      state,
    )}`,
  )}
`;

  if (state.warnings.length > 0) {
    deployingMessage += `\n${styleText(
      "yellow",
      "Warning - previously executed futures are not in the module:",
    )}\n`;

    deployingMessage += state.warnings
      .map((futureId) => styleText("yellow", ` - ${futureId}`))
      .join("\n");

    deployingMessage += "\n";
  }

  return deployingMessage;
}

function _calculateStrategySuffix(state: UiState) {
  if (state.strategy === "basic") {
    return "";
  }

  return ` with strategy ${state.strategy ?? "unknown"}`;
}

import type { Artifact, BuildInfo } from "@nomicfoundation/ignition-core";

import path from "node:path";

import { HardhatError } from "@nomicfoundation/hardhat-errors";
import {
  exists,
  readdir,
  readJsonFile,
} from "@nomicfoundation/hardhat-utils/fs";

export async function verifyArtifactsVersion(
  deploymentDir: string | undefined,
): Promise<void> {
  const artifactsDir = `${deploymentDir}/artifacts`;

  if (deploymentDir === undefined || !(await exists(artifactsDir))) {
    return;
  }

  for (const filename of await readdir(artifactsDir)) {
    if (filename.endsWith(".dbg.json")) {
      continue;
    }

    const artifactPath = path.join(artifactsDir, filename);
    const artifact: Artifact = await readJsonFile(artifactPath);

    if (artifact._format === "hh-sol-artifact-1") {
      throw new HardhatError(
        HardhatError.ERRORS.IGNITION.GENERAL.ARTIFACT_MIGRATION_NEEDED,
        {
          deploymentId: deploymentDir.split(path.sep).pop(),
        },
      );
    }
  }

  const buildInfoDir = `${deploymentDir}/build-info`;

  if (!(await exists(buildInfoDir))) {
    return;
  }

  for (const filename of await readdir(buildInfoDir)) {
    const buildInfoPath = path.join(buildInfoDir, filename);
    const buildInfo: BuildInfo = await readJsonFile(buildInfoPath);

    if (buildInfo._format === "hh-sol-build-info-1") {
      throw new HardhatError(
        HardhatError.ERRORS.IGNITION.GENERAL.ARTIFACT_MIGRATION_NEEDED,
        {
          deploymentId: deploymentDir.split(path.sep).pop(),
        },
      );
    }
  }
}

import type { SerializedIgnitionModule } from "@nomicfoundation/ignition-core";

import { createRequire } from "node:module";
import path from "node:path";

import { HardhatError } from "@nomicfoundation/hardhat-errors";
import {
  ensureDir,
  exists,
  readUtf8File,
  writeUtf8File,
} from "@nomicfoundation/hardhat-utils/fs";

export async function writeVisualization(
  visualizationPayload: {
    module: SerializedIgnitionModule;
    batches: string[][];
  },
  { cacheDir }: { cacheDir: string },
): Promise<void> {
  const require = createRequire(import.meta.url);
  const templateDir = path.join(
    require.resolve("@nomicfoundation/ignition-ui/package.json"),
    "../dist",
  );

  const templateDirExists = await exists(templateDir);

  if (!templateDirExists) {
    throw new HardhatError(
      HardhatError.ERRORS.IGNITION.INTERNAL.VISUALIZATION_TEMPLATE_DIR_NOT_FOUND,
      {
        templateDir,
      },
    );
  }

  const visualizationDir = path.join(cacheDir, "visualization");

  await ensureDir(visualizationDir);

  const indexHtml = await readUtf8File(path.join(templateDir, "index.html"));
  const updatedHtml = indexHtml
    .toString()
    .replace('{ "unloaded": true }', JSON.stringify(visualizationPayload));

  await writeUtf8File(path.join(visualizationDir, "index.html"), updatedHtml);
}

import type { KeystoreConsoleLog, KeystoreLoader } from "../types.js";
import type { HardhatRuntimeEnvironment } from "hardhat/types/hre";
import type { NewTaskActionFunction } from "hardhat/types/tasks";

import { UserDisplayMessages } from "../ui/user-display-messages.js";
import { setupKeystoreLoaderFrom } from "../utils/setup-keystore-loader-from.js";

interface TaskListArguments {
  dev: boolean;
}

const taskList: NewTaskActionFunction<TaskListArguments> = async (
  args,
  hre: HardhatRuntimeEnvironment,
): Promise<void> => {
  const keystoreLoader = setupKeystoreLoaderFrom(hre, args.dev);

  await list(args, keystoreLoader);
};

export const list = async (
  { dev }: TaskListArguments,
  keystoreLoader: KeystoreLoader,
  consoleLog: KeystoreConsoleLog = console.log,
): Promise<void> => {
  if (!(await keystoreLoader.isKeystoreInitialized())) {
    consoleLog(UserDisplayMessages.displayNoKeystoreSetErrorMessage(dev));
    process.exitCode = 1;
    return;
  }

  const keystore = await keystoreLoader.loadKeystore();

  const keys = await keystore.listUnverifiedKeys();

  if (keys.length === 0) {
    consoleLog(UserDisplayMessages.displayNoKeysInfoMessage(dev));
    return;
  }

  consoleLog(UserDisplayMessages.displayKeyListInfoMessage(keys, dev));
};

export default taskList;

import type {
  FailedJsonRpcResponse,
  JsonRpcResponse,
  RequestArguments,
  SuccessfulJsonRpcResponse,
} from "hardhat/types/providers";

import { HardhatError } from "@nomicfoundation/hardhat-errors";
import { isObject } from "@nomicfoundation/hardhat-utils/lang";

export function isJsonRpcResponse(
  payload: unknown,
): payload is JsonRpcResponse {
  if (!isObject(payload)) {
    return false;
  }

  if (payload.jsonrpc !== "2.0") {
    return false;
  }

  if (
    typeof payload.id !== "number" &&
    typeof payload.id !== "string" &&
    payload.id !== null
  ) {
    return false;
  }

  if (payload.result === undefined && payload.error === undefined) {
    return false;
  }

  if (payload.error !== undefined) {
    if (!isObject(payload.error)) {
      return false;
    }

    if (typeof payload.error.code !== "number") {
      return false;
    }

    if (typeof payload.error.message !== "string") {
      return false;
    }
  }

  return true;
}

export function isSuccessfulJsonRpcResponse(
  payload: JsonRpcResponse,
): payload is SuccessfulJsonRpcResponse {
  return "result" in payload;
}

export function isFailedJsonRpcResponse(
  payload: JsonRpcResponse,
): payload is FailedJsonRpcResponse {
  return "error" in payload && payload.error !== undefined;
}

export function getRequestParams(
  requestArguments: RequestArguments,
): unknown[] {
  if (requestArguments.params === undefined) {
    return [];
  }

  if (Array.isArray(requestArguments.params)) {
    return requestArguments.params;
  }

  throw new HardhatError(
    HardhatError.ERRORS.CORE.NETWORK.INVALID_REQUEST_PARAMS,
  );
}

import { HardhatError } from "@nomicfoundation/hardhat-errors";
import {
  isAddress,
  isValidChecksumAddress,
} from "@nomicfoundation/hardhat-utils/eth";

export function assertHexString(hexString: string): void {
  if (typeof hexString !== "string" || !/^0x[0-9a-fA-F]*$/.test(hexString)) {
    throw new HardhatError(
      HardhatError.ERRORS.NETWORK_HELPERS.GENERAL.INVALID_HEX_STRING,
      {
        value: hexString,
      },
    );
  }
}

export function assertTxHash(hexString: string): void {
  assertHexString(hexString);

  if (hexString.length !== 66) {
    throw new HardhatError(
      HardhatError.ERRORS.NETWORK_HELPERS.GENERAL.INVALID_TX_HASH,
      {
        value: hexString,
      },
    );
  }
}

export async function assertValidAddress(address: string): Promise<void> {
  if (!isAddress(address)) {
    throw new HardhatError(
      HardhatError.ERRORS.NETWORK_HELPERS.GENERAL.INVALID_ADDRESS,
      {
        value: address,
      },
    );
  }

  const hasChecksum = address !== address.toLowerCase();

  if (hasChecksum && !(await isValidChecksumAddress(address))) {
    throw new HardhatError(
      HardhatError.ERRORS.NETWORK_HELPERS.GENERAL.INVALID_CHECKSUM_ADDRESS,
      {
        value: address,
      },
    );
  }
}

export function assertLargerThan(a: bigint, b: bigint): void;
export function assertLargerThan(a: number, b: number): void;
export function assertLargerThan(a: number | bigint, b: number | bigint): void {
  if (a <= b) {
    throw new HardhatError(
      HardhatError.ERRORS.NETWORK_HELPERS.GENERAL.BLOCK_NUMBER_SMALLER_THAN_CURRENT,
      {
        newValue: a,
        currentValue: b,
      },
    );
  }
}

import type { NumberLike } from "../types.js";

import { HardhatError } from "@nomicfoundation/hardhat-errors";
import { toBigInt as toBigIntUtil } from "@nomicfoundation/hardhat-utils/bigint";

export function toNumber(x: NumberLike): number {
  return Number(toRpcQuantity(x));
}

export async function toBigInt(x: NumberLike): Promise<bigint> {
  return toBigIntUtil(toRpcQuantity(x));
}

export function toRpcQuantity(x: NumberLike): string {
  let hex: string;

  if (typeof x === "number" || typeof x === "bigint") {
    if (x < 0) {
      throw new HardhatError(
        HardhatError.ERRORS.NETWORK_HELPERS.GENERAL.CANNOT_CONVERT_NEGATIVE_NUMBER_TO_RPC_QUANTITY,
        {
          value: x,
        },
      );
    }

    hex = `0x${x.toString(16)}`;
  } else if (typeof x === "string") {
    if (!x.startsWith("0x")) {
      throw new HardhatError(
        HardhatError.ERRORS.NETWORK_HELPERS.GENERAL.ONLY_ALLOW_0X_PREFIXED_STRINGS,
      );
    }
    hex = x;
  } else {
    throw new HardhatError(
      HardhatError.ERRORS.NETWORK_HELPERS.GENERAL.CANNOT_CONVERT_TO_RPC_QUANTITY,
      {
        value: x,
      },
    );
  }

  if (hex === "0x0") {
    return hex;
  }

  return hex.startsWith("0x") ? hex.replace(/0x0+/, "0x") : `0x${hex}`;
}

