import type {
  Hex,
  ReadContractReturnType,
  WriteContractReturnType,
} from "viem";

import assert from "node:assert/strict";

import { ensureError } from "@nomicfoundation/hardhat-utils/error";
import { decodeErrorResult } from "viem";

import { isKnownErrorSelector } from "./error-string.js";
import { extractRevertError } from "./extract-revert-error.js";

export async function handleRevert(
  contractFn: Promise<ReadContractReturnType | WriteContractReturnType>,
): Promise<
  | {
      args: string[];
      isPanicError: boolean;
      data: Hex;
    }
  | {
      errorWithoutReason: true;
    }
> {
  try {
    await contractFn;
  } catch (error) {
    ensureError(error);

    const rawError = extractRevertError(error);

    if (
      isKnownErrorSelector(rawError.data) === false &&
      rawError.data !== "0x"
    ) {
      assert.fail(
        `The function was expected to revert with a non custom error, but it instead reverted with a custom error. ${rawError.message}`,
      );
    }

    if (rawError.data === "0x") {
      return {
        errorWithoutReason: true,
      };
    }

    const decodedError = decodeErrorResult({ data: rawError.data });

    return {
      args: decodedError.args.map((a) => String(a)),
      isPanicError: decodedError.errorName === "Panic",
      data: rawError.data,
    };
  }

  assert.fail("The function was expected to revert, but it did not revert");
}

import assert from "node:assert/strict";

import { ensureError } from "@nomicfoundation/hardhat-utils/error";
import { deepEqual } from "@nomicfoundation/hardhat-utils/lang";

// EIP-55 addresses are 0x-prefixed 40 hex chars; case carries only checksum info.
const ADDRESS_REGEX = /^0x[0-9a-fA-F]{40}$/;

function isAddressLike(value: unknown): value is string {
  return typeof value === "string" && ADDRESS_REGEX.test(value);
}

export function anyValue() {
  return true;
}

export async function isArgumentMatch(
  actualArgs: any[],
  expectedArgs: any[],
): Promise<boolean> {
  assert.ok(
    actualArgs.length === expectedArgs.length,
    `${actualArgs.length} arguments emitted, but ${expectedArgs.length} expected`,
  );

  for (let index = 0; index < actualArgs.length; index++) {
    const emittedArg = actualArgs[index];
    const expectedArg = expectedArgs[index];

    if (typeof expectedArg === "function") {
      try {
        if (expectedArg(emittedArg) !== true) {
          return false;
        }
      } catch (e) {
        ensureError(e);
        assert.fail(
          `The predicate of index ${index} threw when called: ${e.message}`,
        );
      }
    } else if (isAddressLike(emittedArg) && isAddressLike(expectedArg)) {
      if (emittedArg === expectedArg) {
        continue;
      }

      if (emittedArg.toLowerCase() !== expectedArg.toLowerCase()) {
        return false;
      }
    } else {
      if (!(await deepEqual(emittedArg, expectedArg))) {
        return false;
      }
    }
  }

  return true;
}

import type { HardhatRuntimeEnvironmentHooks } from "../../../../types/hooks.js";
import type { GasAnalyticsManagerImplementation as GasAnalyticsManagerImplementationT } from "../gas-analytics-manager.js";

import { setGasAnalyticsManager } from "../helpers/accessors.js";

let GasAnalyticsManagerImplementation:
  | typeof GasAnalyticsManagerImplementationT
  | undefined;

export default async (): Promise<Partial<HardhatRuntimeEnvironmentHooks>> => ({
  created: async (context, hre) => {
    if (
      !context.globalOptions.gasStats &&
      context.globalOptions.gasStatsJson === undefined
    ) {
      return;
    }

    if (GasAnalyticsManagerImplementation === undefined) {
      ({ GasAnalyticsManagerImplementation } = await import(
        "../gas-analytics-manager.js"
      ));
    }

    const gasAnalyticsManager = new GasAnalyticsManagerImplementation(
      hre.config.paths.cache,
    );

    setGasAnalyticsManager(hre, gasAnalyticsManager);

    // NOTE: We register this hook dynamically to avoid a circular dependency
    // between gas-analytics and network-manager plugins. The network-manager
    // checks for the existence of onGasReported handlers to determine if gas
    // analytics is enabled, rather than directly checking the global option.
    hre.hooks.registerHandlers("network", {
      onGasMeasurement: (_context, gasMeasurement) => {
        gasAnalyticsManager.addGasMeasurement(gasMeasurement);
      },
    });
  },
});

import type { GlobalOptionDefinitions } from "../../../types/global-options.js";
import type { Task } from "../../../types/tasks.js";

import { getHardhatVersion } from "../../utils/package.js";

import {
  GLOBAL_NAME_PADDING,
  getLongestNameLength,
  getSection,
  parseTasks,
  parseGlobalOptions,
} from "./utils.js";

export async function getGlobalHelpString(
  rootTasks: Map<string, Task>,
  globalOptionDefinitions: GlobalOptionDefinitions,
): Promise<string> {
  const version = await getHardhatVersion();

  const { tasks, subtasks } = parseTasks(rootTasks);

  const globalOptions = parseGlobalOptions(globalOptionDefinitions);

  const namePadding =
    getLongestNameLength([...tasks, ...subtasks, ...globalOptions]) +
    GLOBAL_NAME_PADDING;

  let output = `Hardhat version ${version}

Usage: hardhat [GLOBAL OPTIONS] <TASK> [SUBTASK] [TASK OPTIONS] [--] [TASK ARGUMENTS]
`;

  if (tasks.length > 0) {
    output += getSection("AVAILABLE TASKS", tasks, namePadding);
  }

  if (subtasks.length > 0) {
    output += getSection("AVAILABLE SUBTASKS", subtasks, namePadding);
  }

  output += getSection("GLOBAL OPTIONS", globalOptions, namePadding);

  output += `\nTo get help for a specific task run: npx hardhat <TASK> [SUBTASK] --help`;

  return output;
}

import type { AnalyticsFile } from "./types.js";

import path from "node:path";

import { createDebug } from "@nomicfoundation/hardhat-utils/debug";
import {
  exists,
  readJsonFile,
  writeJsonFile,
} from "@nomicfoundation/hardhat-utils/fs";
import { getTelemetryDir } from "@nomicfoundation/hardhat-utils/global-dir";

const log = createDebug("hardhat:core:cli:telemetry:analytics:utils");

const ANALYTICS_FILE_NAME = "analytics.json";

export async function getAnalyticsClientId(): Promise<string> {
  let clientId = await readAnalyticsClientId();

  if (clientId === undefined) {
    log("Client Id not found, generating a new one");

    clientId = crypto.randomUUID();
    await writeAnalyticsClientId(clientId);
  }

  return clientId;
}

async function readAnalyticsClientId(): Promise<string | undefined> {
  const globalTelemetryDir = await getTelemetryDir();
  const filePath = path.join(globalTelemetryDir, ANALYTICS_FILE_NAME);

  log(`Looking up Client Id at '${filePath}'`);

  if ((await exists(filePath)) === false) {
    return undefined;
  }

  const data: AnalyticsFile = await readJsonFile(filePath);
  const clientId = data.analytics.clientId;

  log(`Client Id found: ${clientId}`);

  return clientId;
}

async function writeAnalyticsClientId(clientId: string): Promise<void> {
  const globalTelemetryDir = await getTelemetryDir();
  const filePath = path.join(globalTelemetryDir, ANALYTICS_FILE_NAME);
  await writeJsonFile(filePath, {
    analytics: {
      clientId,
    },
  });

  log(`Stored clientId '${clientId}'`);
}

