import type {
  ContractAtFuture,
  ContractDeploymentFuture,
  LibraryDeploymentFuture,
  NamedArtifactContractAtFuture,
  NamedArtifactContractDeploymentFuture,
  NamedArtifactLibraryDeploymentFuture,
} from "../../../types/module.js";
import type {
  ReconciliationContext,
  ReconciliationFutureResultFailure,
} from "../types.js";

import {
  ExecutionStatus,
  type ContractAtExecutionState,
  type DeploymentExecutionState,
} from "../../execution/types/execution-state.js";
import { fail, getBytecodeWithoutMetadata } from "../utils.js";

export async function reconcileArtifacts(
  future:
    | NamedArtifactContractDeploymentFuture<string>
    | ContractDeploymentFuture
    | NamedArtifactLibraryDeploymentFuture<string>
    | LibraryDeploymentFuture
    | NamedArtifactContractAtFuture<string>
    | ContractAtFuture,
  exState: DeploymentExecutionState | ContractAtExecutionState,
  context: ReconciliationContext,
): Promise<ReconciliationFutureResultFailure | undefined> {
  if (exState.status === ExecutionStatus.SUCCESS) {
    return;
  }

  const moduleArtifact =
    "artifact" in future
      ? future.artifact
      : await context.artifactResolver.loadArtifact(future.contractName);

  const storedArtifact = await context.deploymentLoader.loadArtifact(
    exState.artifactId,
  );

  const moduleArtifactBytecode = getBytecodeWithoutMetadata(
    moduleArtifact.bytecode,
  );
  const storedArtifactBytecode = getBytecodeWithoutMetadata(
    storedArtifact.bytecode,
  );

  if (moduleArtifactBytecode !== storedArtifactBytecode) {
    return fail(future, "Artifact bytecodes have been changed");
  }
}

import type {
  ContractDeploymentFuture,
  LibraryDeploymentFuture,
  NamedArtifactContractDeploymentFuture,
  NamedArtifactLibraryDeploymentFuture,
} from "../../../types/module.js";
import type { DeploymentExecutionState } from "../../execution/types/execution-state.js";
import type {
  ReconciliationContext,
  ReconciliationFutureResultFailure,
} from "../types.js";

import { resolveLibraries } from "../../execution/future-processor/helpers/future-resolvers.js";
import { fail } from "../utils.js";

export function reconcileLibraries(
  future:
    | NamedArtifactContractDeploymentFuture<string>
    | ContractDeploymentFuture
    | NamedArtifactLibraryDeploymentFuture<string>
    | LibraryDeploymentFuture,
  exState: DeploymentExecutionState,
  context: ReconciliationContext,
): ReconciliationFutureResultFailure | undefined {
  const futureLibraries = resolveLibraries(
    future.libraries,
    context.deploymentState,
  );

  for (const [libName, exStateLib] of Object.entries(exState.libraries)) {
    if (futureLibraries[libName] === undefined) {
      return fail(future, `Library ${libName} has been removed`);
    }

    if (futureLibraries[libName] !== exStateLib) {
      return fail(future, `Library ${libName}'s address has been changed`);
    }
  }

  for (const libName of Object.keys(futureLibraries)) {
    if (exState.libraries[libName] === undefined) {
      return fail(future, `Library ${libName} has been added`);
    }
  }
}

import type { ReconciliationFutureResult } from "./types.js";
import type { Future } from "../../types/module.js";
import type { DeploymentState } from "../execution/types/deployment-state.js";
import type { ExecutionState } from "../execution/types/execution-state.js";

import { difference } from "lodash-es";

import { ExecutionStatus } from "../execution/types/execution-state.js";

import { fail } from "./utils.js";

export function reconcileDependencyRules(
  future: Future,
  executionState: ExecutionState,
  context: { deploymentState: DeploymentState },
): ReconciliationFutureResult {
  const previousDeps: string[] = [...executionState.dependencies];
  const currentDeps: string[] = [...future.dependencies].map((f) => f.id);

  const additionalDeps = difference(currentDeps, previousDeps);

  for (const additionalDep of additionalDeps) {
    const additionalExecutionState =
      context.deploymentState.executionStates[additionalDep];

    if (additionalExecutionState === undefined) {
      return fail(
        future,
        `A dependency from ${future.id} to ${additionalDep} has been added. The former has started executing before the latter started executing, so this change is incompatible.`,
      );
    }

    // TODO: Check that is was successfully executed before `executionState` was created.
    if (additionalExecutionState.status === ExecutionStatus.SUCCESS) {
      continue;
    }

    return fail(
      future,
      `A dependency from ${future.id} to ${additionalDep} has been added, and both futures had already started executing, so this change is incompatible`,
    );
  }

  return { success: true };
}
